import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"巴菲特致股东信核心总结 · 2002年","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2002年/核心总结.md","filePath":"01_letters/2002年/核心总结.md"}'),r={name:"01_letters/2002年/核心总结.md"};function o(h,a,n,d,u,s){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="巴菲特致股东信核心总结-·-2002年" tabindex="-1">巴菲特致股东信核心总结 · 2002年 <a class="header-anchor" href="#巴菲特致股东信核心总结-·-2002年" aria-label="Permalink to &quot;巴菲特致股东信核心总结 · 2002年&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净值增长61亿美元，每股账面价值增长10.0%</li><li>过去38年每股账面价值年复合增长率22.2%</li><li>相对结果超过标普500指数32.1个百分点</li></ul><h2 id="年度成就" tabindex="-1">年度成就 <a class="header-anchor" href="#年度成就" aria-label="Permalink to &quot;年度成就&quot;">​</a></h2><ul><li>非保险业务月度税前利润等于十年前的年度利润（2.72亿美元）</li><li>浮存金增加57亿美元至412亿美元，成本仅1%</li><li>收购重要新业务，以优秀到卓越的经济特征运营</li><li>可交易证券表现超过大多数指数</li></ul><h2 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h2><h3 id="已完成收购" tabindex="-1">已完成收购 <a class="header-anchor" href="#已完成收购" aria-label="Permalink to &quot;已完成收购&quot;">​</a></h3><ol><li><strong>Albecca/Larson-Juhl</strong> - 美国定制画框领导者</li><li><strong>Fruit of the Loom</strong> - 男童内衣占美国33.3%销量</li><li><strong>CTB</strong> - 家禽、生猪、蛋品生产设备全球领导者</li><li><strong>Garan</strong> - 儿童服装制造商（Garanimals®品牌）</li><li><strong>The Pampered Chef</strong> - 家庭厨具演示销售，年销售额超7亿美元</li></ol><h3 id="中美能源收购" tabindex="-1">中美能源收购 <a class="header-anchor" href="#中美能源收购" aria-label="Permalink to &quot;中美能源收购&quot;">​</a></h3><ul><li><strong>Kern River管道</strong> - 正在12亿美元扩建，输送能力翻倍</li><li><strong>Northern Natural Gas管道</strong> - 16,600英里，从安然/Dynegy回归奥马哈</li></ul><h3 id="收购哲学" tabindex="-1">收购哲学 <a class="header-anchor" href="#收购哲学" aria-label="Permalink to &quot;收购哲学&quot;">​</a></h3><ul><li>没有&quot;退出&quot;战略，买入是为了持有</li><li>伯克希尔通常是卖方的首选甚至唯一选择</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金发展" tabindex="-1">浮存金发展 <a class="header-anchor" href="#浮存金发展" aria-label="Permalink to &quot;浮存金发展&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>浮存金（百万美元）</th></tr></thead><tbody><tr><td>1967</td><td>20</td></tr><tr><td>1997</td><td>7,386</td></tr><tr><td>2000</td><td>27,871</td></tr><tr><td>2002</td><td>41,224</td></tr></tbody></table><h3 id="通用再保险恢复" tabindex="-1">通用再保险恢复 <a class="header-anchor" href="#通用再保险恢复" aria-label="Permalink to &quot;通用再保险恢复&quot;">​</a></h3><ul><li>乔·布兰登和塔德·蒙特罗斯恢复承保纪律</li><li>核、化学、生物风险聚集已降至可容忍水平</li><li>2002年计提13.1亿美元纠正早年准备金错误</li><li>财务实力AAA评级，三大竞争对手均被降级</li></ul><h3 id="阿吉特·贾恩的再保险" tabindex="-1">阿吉特·贾恩的再保险 <a class="header-anchor" href="#阿吉特·贾恩的再保险" aria-label="Permalink to &quot;阿吉特·贾恩的再保险&quot;">​</a></h3><ul><li>134亿美元浮存金，仅20名员工</li><li>承保利润5.34亿美元</li><li>石棉和环境损失准备金80%来自有上限合同</li></ul><h3 id="盖可保险" tabindex="-1">盖可保险 <a class="header-anchor" href="#盖可保险" aria-label="Permalink to &quot;盖可保险&quot;">​</a></h3><ul><li>保费收入从1996年的29亿美元增至69亿美元</li><li>互联网业务增长75%</li><li>19,162名员工获得工资19%的利润分享</li></ul><h2 id="衍生品警告" tabindex="-1">衍生品警告 <a class="header-anchor" href="#衍生品警告" aria-label="Permalink to &quot;衍生品警告&quot;">​</a></h2><h3 id="核心观点" tabindex="-1">核心观点 <a class="header-anchor" href="#核心观点" aria-label="Permalink to &quot;核心观点&quot;">​</a></h3><ul><li>衍生品是&quot;定时炸弹&quot;，对各方和经济体系都是如此</li><li>容易进入，几乎不可能退出</li><li>&quot;按模型计价&quot;可能退化成&quot;按神话计价&quot;</li></ul><h3 id="衍生品风险" tabindex="-1">衍生品风险 <a class="header-anchor" href="#衍生品风险" aria-label="Permalink to &quot;衍生品风险&quot;">​</a></h3><ul><li>加剧公司因无关原因遇到的麻烦</li><li>要求信用降级的公司立即提供抵押品</li><li>创造类似再保险转分保的风险聚集</li><li>&quot;大规模杀伤性金融武器&quot;</li></ul><h3 id="通用再保险证券" tabindex="-1">通用再保险证券 <a class="header-anchor" href="#通用再保险证券" aria-label="Permalink to &quot;通用再保险证券&quot;">​</a></h3><ul><li>年底有14,384份未完成合约，涉及672个交易对手</li><li>正在清算中，但需要多年才能完全退出</li></ul><h2 id="公司治理" tabindex="-1">公司治理 <a class="header-anchor" href="#公司治理" aria-label="Permalink to &quot;公司治理&quot;">​</a></h2><h3 id="董事责任" tabindex="-1">董事责任 <a class="header-anchor" href="#董事责任" aria-label="Permalink to &quot;董事责任&quot;">​</a></h3><ul><li>解雇平庸或更差的管理者</li><li>阻止贪婪管理者越界掏股东口袋</li><li>协商合理的管理费（共同基金董事的失败案例）</li></ul><h3 id="董事素质三要素" tabindex="-1">董事素质三要素 <a class="header-anchor" href="#董事素质三要素" aria-label="Permalink to &quot;董事素质三要素&quot;">​</a></h3><ol><li>商业智慧</li><li>对企业的兴趣</li><li>以股东为导向</li></ol><h3 id="董事薪酬问题" tabindex="-1">董事薪酬问题 <a class="header-anchor" href="#董事薪酬问题" aria-label="Permalink to &quot;董事薪酬问题&quot;">​</a></h3><ul><li>费用占收入20%以上的董事如何独立？</li><li>伯克希尔董事薪酬微薄，不提供高管责任保险</li></ul><h2 id="审计委员会建议" tabindex="-1">审计委员会建议 <a class="header-anchor" href="#审计委员会建议" aria-label="Permalink to &quot;审计委员会建议&quot;">​</a></h2><h3 id="四个关键问题" tabindex="-1">四个关键问题 <a class="header-anchor" href="#四个关键问题" aria-label="Permalink to &quot;四个关键问题&quot;">​</a></h3><ol><li>如果审计师全权负责编制财务报表，他们会以不同方式编制吗？</li><li>如果审计师是投资者，他能获得理解财务表现的基本信息吗？</li><li>公司是否遵循审计师本人会遵循的内部审计程序？</li><li>审计师是否知道任何转移收入或费用的行动？</li></ol><h2 id="投资组合" tabindex="-1">投资组合 <a class="header-anchor" href="#投资组合" aria-label="Permalink to &quot;投资组合&quot;">​</a></h2><p>主要持仓：</p><ul><li>可口可乐：87.68亿美元</li><li>美国运通：53.59亿美元</li><li>吉列：29.15亿美元</li><li>富国银行：24.97亿美元</li></ul><h3 id="投资态度" tabindex="-1">投资态度 <a class="header-anchor" href="#投资态度" aria-label="Permalink to &quot;投资态度&quot;">​</a></h3><ul><li>股票方面做得很少</li><li>不相信主要持仓被低估</li><li>需要10%税前回报才会行动</li><li>垃圾债券投资增加六倍至83亿美元</li></ul><h2 id="非保险业务亮点" tabindex="-1">非保险业务亮点 <a class="header-anchor" href="#非保险业务亮点" aria-label="Permalink to &quot;非保险业务亮点&quot;">​</a></h2><h3 id="建筑相关业务" tabindex="-1">建筑相关业务 <a class="header-anchor" href="#建筑相关业务" aria-label="Permalink to &quot;建筑相关业务&quot;">​</a></h3><ul><li>Acme Brick、Benjamin Moore、Johns Manville、MiTek、Shaw合计税前利润9.41亿美元</li><li>Shaw利润从2.92亿美元增至4.24亿美元</li></ul><h3 id="中美能源" tabindex="-1">中美能源 <a class="header-anchor" href="#中美能源" aria-label="Permalink to &quot;中美能源&quot;">​</a></h3><ul><li>资产180亿美元</li><li>最大的非保险利润流</li><li>将运输美国约8%的天然气</li></ul><h3 id="netjets" tabindex="-1">NetJets <a class="header-anchor" href="#netjets" aria-label="Permalink to &quot;NetJets&quot;">​</a></h3><ul><li>行业份额75%</li><li>机队飞行1.327亿海里，覆盖130个国家</li><li>通用电气是最大客户</li></ul><h2 id="管理哲学" tabindex="-1">管理哲学 <a class="header-anchor" href="#管理哲学" aria-label="Permalink to &quot;管理哲学&quot;">​</a></h2><h3 id="球童埃迪·贝内特的故事" tabindex="-1">球童埃迪·贝内特的故事 <a class="header-anchor" href="#球童埃迪·贝内特的故事" aria-label="Permalink to &quot;球童埃迪·贝内特的故事&quot;">​</a></h3><ul><li>1919年白袜队→1920年道奇队→1921年扬基队</li><li>教训：要成为赢家，就与赢家共事</li><li>1927年因扬基队世界大赛份额获得700美元</li></ul><h3 id="老狗新把戏" tabindex="-1">&quot;老狗新把戏&quot; <a class="header-anchor" href="#老狗新把戏" aria-label="Permalink to &quot;&quot;老狗新把戏&quot;&quot;">​</a></h3><ul><li>六位75岁以上的管理者</li><li>鲍勃·肖和巴菲特都是72岁</li><li>很难教老狗新把戏，也不想教</li></ul><h2 id="其他要点" tabindex="-1">其他要点 <a class="header-anchor" href="#其他要点" aria-label="Permalink to &quot;其他要点&quot;">​</a></h2><ul><li>2002年没有超级灾难（有利因素）</li><li>债券市场有利（有利因素）</li><li>&quot;形式上&quot;盈利实际低于报告盈利</li><li>总部员工14.8人</li></ul><hr><p><em>核心要点总结完成</em></p>',59)])])}const b=l(r,[["render",o]]);export{q as __pageData,b as default};
